import{_ as i,o,c as t,ai as n,ar as a,as as s,at as r}from"./chunks/framework.DsLHkhEs.js";const b=JSON.parse('{"title":"Instance Info","description":"","frontmatter":{},"headers":[],"relativePath":"Web Client/Main/Instance Info.md","filePath":"Web Client/Main/Instance Info.md"}'),c={name:"Web Client/Main/Instance Info.md"};function l(p,e,d,m,h,u){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="instance-info" tabindex="-1">Instance Info <a class="header-anchor" href="#instance-info" aria-label="Permalink to “Instance Info”">​</a></h1><p>The instance info screen is a small compact popup showing some information about the server and or community in general. As you can see in the screenshot, it will show some general information and has the option to even show some social urls if set, including an email.</p><p><img src="'+a+'" alt="image-20251229133215753"></p><hr><h2 id="importance-of-socials" tabindex="-1">Importance of socials <a class="header-anchor" href="#importance-of-socials" aria-label="Permalink to “Importance of socials”">​</a></h2><p>These social links can be used to grow a community outside of your chat instance and give banned members a possibility to appeal their bans or allow members to contact you or your team for any inquiries.</p><p>Currently supported social urls are:</p><ul><li>Email</li><li>Website</li><li>Subreddit</li><li>Discord Invite</li><li>Github Repo</li><li>Owner name(s)</li></ul><p><img src="'+s+'" alt="image-20251229135211990"></p><hr><h2 id="setting-instance-infos" tabindex="-1">Setting instance infos <a class="header-anchor" href="#setting-instance-infos" aria-label="Permalink to “Setting instance infos”">​</a></h2><p>As of the time of writing, instance information can only be set by manually editing the <code>./configs/config.json</code> file. As seen in the screenshot, you will come across a section called <code>instance</code> where you can edit the properties to your heart&#39;s desire.</p><p>Before setting any infos, keep in mind that:</p><ul><li>the <code>reddit</code> property was designed for subreddits, not accounts or anything else,</li><li>the <code>discord</code> property was made for invite urls with <code>.gg/</code> urls</li><li><code>github</code> was designed for repo urls</li></ul><p>By supplying any other kind of url, it may break the instance info popup.</p><p><img src="'+r+'" alt="image-20251229135500104"></p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><p>To hide unused socials, just set their value to <code>&quot;&quot;</code> as seen with the <code>email</code> and <code>website</code> property.</p></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p></p><p>The <code>name</code> property inside <code>owner</code> also supports HTML</p></div>',18)])])}const g=i(c,[["render",l]]);export{b as __pageData,g as default};
